onChange.script:
if currentValue.value != None:
	self.parent.parent.getChild("CoordinateContainer_sensorType").getChild("Dropdown_sensorType").props.options = currentValue.value
else:
	self.parent.parent.getChild("CoordinateContainer_sensorType").getChild("Dropdown_sensorType").props.options = self.view.custom.models

config.script:
import json
try:
	tenants = system.sitesync.listTenants()
	t = json.loads(tenants)
	options = []

	for tenant in t:
		j = {"label":tenant['tenantName'], "value": tenant['id']}

		options.append(j)

	self.props.options = options
except Exception as e:
	system.perspective.print("Error getting tenants" + str(e))

system.perspective.print(self.session.custom.tenantID)
if self.session.custom.tenantID >= 2:
	try:
		models, mfgList = utils.deviceProfileDropDown.getDeviceProfiles(1)


		self.custom.models = models
		self.custom.mfgs = mfgList

		self.view.custom.sensorType = -1
		self.view.custom.image = None

	except Exception as e:
		system.perspective.print("Error loading models: " + str(e))
else:
	system.perspective.navigate(page="/")
